const sgMail = require('@sendgrid/mail');
const crypto = require('crypto');

// Initialize SendGrid with API key
sgMail.setApiKey(process.env.SENDGRID_API_KEY);

// Configure DKIM signing in SendGrid
// 1. Add authenticated domain in SendGrid dashboard
// 2. Add DNS records for DKIM (s1._domainkey, s2._domainkey)
// 3. Add SPF record: v=spf1 include:sendgrid.net ~all
// 4. Add DMARC record (see below)

// DMARC DNS Configuration (TXT record at _dmarc.example.com)
// v=DMARC1; p=reject; rua=mailto:dmarc-reports@example.com; ruf=mailto:dmarc-forensics@example.com; fo=1; adkim=s; aspf=s; pct=100

// Send email with DKIM signature
async function sendSecureEmail(to, subject, body) {
  const msg = {
    to: to,
    from: {
      email: 'noreply@example.com',
      name: 'Example Corp'
    },
    subject: subject,
    text: body,
    html: `<p>${body}</p>`,
    // Custom headers for tracking
    headers: {
      'X-Message-ID': crypto.randomUUID(),
      'X-Transaction-ID': Date.now().toString()
    },
    // Enable click and open tracking for forensics
    trackingSettings: {
      clickTracking: { enable: true },
      openTracking: { enable: true }
    }
  };

  try {
    const response = await sgMail.send(msg);
    console.log('Email sent with DKIM signature');
    console.log('Message ID:', response[0].headers['x-message-id']);

    // Store email metadata in database for non-repudiation
    await storeEmailMetadata({
      messageId: msg.headers['X-Message-ID'],
      recipient: to,
      subject: subject,
      sentAt: new Date().toISOString(),
      dkimDomain: 'example.com',
      dkimSelector: 's1',
      spfResult: 'pass',
      expectedDKIM: 'pass'
    });

    return response;
  } catch (error) {
    console.error('DKIM signing failed:', error);
    throw error;
  }
}

// Store email metadata for forensic analysis
async function storeEmailMetadata(metadata) {
  // Store in PostgreSQL or Azure Table Storage
  const { Pool } = require('pg');
  const pool = new Pool({ connectionString: process.env.DATABASE_URL });

  await pool.query(
    `INSERT INTO email_audit_log 
     (message_id, recipient, subject, sent_at, dkim_domain, dkim_selector, spf_result, dmarc_expected)
     VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
    [
      metadata.messageId,
      metadata.recipient,
      metadata.subject,
      metadata.sentAt,
      metadata.dkimDomain,
      metadata.dkimSelector,
      metadata.spfResult,
      metadata.expectedDKIM
    ]
  );
}

