module.exports = { sendSecureEmail, parseDMARCReport };

const { SESv2Client, SendEmailCommand } = require('@aws-sdk/client-sesv2');
const { S3Client, PutObjectCommand } = require('@aws-sdk/client-s3');
const crypto = require('crypto');

const sesClient = new SESv2Client({ region: 'us-east-1' });
const s3Client = new S3Client({ region: 'us-east-1' });

// Enable DKIM in SES Console:
// 1. Verify domain: SES > Identities > Create identity
// 2. Enable DKIM: Identity > Authentication > DKIM signatures
// 3. Add CNAME records to DNS from SES console

async function sendEmailWithForensics(to, subject, body) {
  const messageId = crypto.randomUUID();
  const timestamp = new Date().toISOString();

  // Configure email with DKIM
  const emailParams = {
    FromEmailAddress: 'noreply@example.com',
    Destination: {
      ToAddresses: [to]
    },
    Content: {
      Simple: {
        Subject: { Data: subject },
        Body: {
          Text: { Data: body },
          Html: { Data: `<html><body><p>${body}</p></body></html>` }
        }
      }
    },
    // Enable configuration set for logging
    ConfigurationSetName: 'forensic-logging',
    // Add custom headers for tracking
    EmailTags: [
      { Name: 'message-id', Value: messageId },
      { Name: 'sent-timestamp', Value: timestamp }
    ]
  };

  try {
    // Send email via SES with DKIM
    const response = await sesClient.send(new SendEmailCommand(emailParams));
    console.log('Email sent with DKIM:', response.MessageId);

    // Store email metadata for forensics
    const forensicData = {
      sesMessageId: response.MessageId,
      customMessageId: messageId,
      recipient: to,
      subject: subject,
      sentAt: timestamp,
      dkimEnabled: true,
      dkimDomain: 'example.com',
      expectedAuthResults: {
        dkim: 'pass',
        spf: 'pass',
        dmarc: 'pass'
      },
      emailBody: body
    };

    // Store in S3 for long-term retention (legal compliance)
    await storeForensicLog(forensicData);

    return response;
  } catch (error) {
    console.error('SES DKIM email failed:', error);
    throw error;
  }
}

// Store forensic logs in S3 with encryption
async function storeForensicLog(logData) {
  const s3Key = `email-forensics/${new Date().toISOString().split('T')[0]}/${logData.customMessageId}.json`;

  const params = {
    Bucket: 'email-forensic-logs',
    Key: s3Key,
    Body: JSON.stringify(logData, null, 2),
    ContentType: 'application/json',
    // Enable server-side encryption
    ServerSideEncryption: 'AES256',
    // Add metadata for searchability
    Metadata: {
      'message-id': logData.customMessageId,
      'recipient': logData.recipient,
      'sent-date': logData.sentAt
    },
    // Set legal hold for 7 years (compliance)
    ObjectLockMode: 'COMPLIANCE',
    ObjectLockRetainUntilDate: new Date(Date.now() + 7 * 365 * 24 * 60 * 60 * 1000)
  };

  await s3Client.send(new PutObjectCommand(params));
  console.log('Forensic log stored:', s3Key);
}

// Process SES Event Notifications (SNS)
// Configure SNS topic for SES events: Bounce, Complaint, Delivery, Send, Reject
function processSESEvent(snsMessage) {
  const event = JSON.parse(snsMessage.Message);

  switch (event.eventType) {
    case 'Delivery':
      console.log('Email delivered with DKIM:', event.mail.messageId);
      // Verify DKIM passed
      if (event.delivery.dkimSignatureVerdict !== 'PASS') {
        console.warn('DKIM signature failed:', event.mail.messageId);
      }
      break;

    case 'Bounce':
      if (event.bounce.bounceType === 'Permanent') {
        console.error('Permanent bounce (possibly DKIM failure):', event.mail.messageId);
      }
      break;

    case 'Complaint':
      console.warn('Spam complaint received:', event.mail.messageId);
      break;
  }
}

// CloudWatch Logs Insights query for DKIM failures
const CLOUDWATCH_QUERY = `
fields @timestamp, mail.messageId, mail.destination, delivery.dkimSignatureVerdict
| filter eventType = "Delivery" and delivery.dkimSignatureVerdict != "PASS"
| sort @timestamp desc
| limit 100
`;

module.exports = { sendEmailWithForensics, processSESEvent };
